#!/usr/bin/env pwshDescribe 'Post-Session Learning Integration Tests' {    BeforeAll {        $script:root = $PSScriptRoot | Split-Path -Parent | Split-Path -Parent        $script:postSessionLearning = Join-Path $script:root 'scripts\utilities\ENGRAM\post-session-learning.ps1'        $script:tempRoot = Join-Path $script:root 'tmp-post-session-learning-tests'        $script:originalGentleVanguardBaseDir = $env:GENTLE_VANGUARD_BASE_DIR    }    BeforeEach {        if (Test-Path $script:tempRoot) {            Remove-Item -Path $script:tempRoot -Recurse -Force -ErrorAction SilentlyContinue        }        New-Item -ItemType Directory -Path $script:tempRoot -Force | Out-Null    }    AfterEach {        if ($null -eq $script:originalGentleVanguardBaseDir) {            Remove-Item Env:GENTLE_VANGUARD_BASE_DIR -ErrorAction SilentlyContinue        } else {            $env:GENTLE_VANGUARD_BASE_DIR = $script:originalGentleVanguardBaseDir        }        if (Test-Path $script:tempRoot) {            Remove-Item -Path $script:tempRoot -Recurse -Force -ErrorAction SilentlyContinue        }    }    function New-TestWorkspace {        param(            [string]$Path,            [switch]$CreateSummaryDir        )        $configDir = Join-Path $Path 'config'        $skillsDir = Join-Path $Path 'skills'        $businessDir = Join-Path $skillsDir 'business'        $localProposalDir = Join-Path $Path '.local\improvement-proposals'        New-Item -ItemType Directory -Path $configDir -Force | Out-Null        New-Item -ItemType Directory -Path $businessDir -Force | Out-Null        New-Item -ItemType Directory -Path $localProposalDir -Force | Out-Null        if ($CreateSummaryDir) {            New-Item -ItemType Directory -Path (Join-Path $Path 'scripts\.session') -Force | Out-Null        }        return [pscustomobject]@{            ConfigDir = $configDir            SkillsDir = $skillsDir            BusinessDir = $businessDir            ProposalDir = $localProposalDir        }    }    Context 'Proposal generation and backlog handling' {        It 'creates improvement proposals for missing business skill directories and keeps a learning log' {            $workspace = New-TestWorkspace -Path $script:tempRoot            $skillsIndexPath = Join-Path $workspace.SkillsDir 'SKILL_INDEX.md'            $businessSkillIndexPath = Join-Path $workspace.BusinessDir 'SKILL.md'            $pendingProposalPath = Join-Path $workspace.ProposalDir 'pending-proposal.json'            @"- `testing-skill`- `documentation-skill`"@ | Set-Content -Path $skillsIndexPath -Encoding UTF8            @"**sales****finance**"@ | Set-Content -Path $businessSkillIndexPath -Encoding UTF8            New-Item -ItemType Directory -Path (Join-Path $workspace.BusinessDir 'sales') -Force | Out-Null            '{"id":"pending-001","applied":false}' | Set-Content -Path $pendingProposalPath -Encoding UTF8            $env:GENTLE_VANGUARD_BASE_DIR = $script:tempRoot            $null = & $script:postSessionLearning -SessionId 'isolated-learning-proposals' -AutoApplyLow -NoExit 2>&1            $proposalFiles = @(Get-ChildItem -Path $workspace.ProposalDir -Filter 'prop-*.json' -ErrorAction SilentlyContinue)            $proposalFiles.Count | Should -Be 1            $proposal = Get-Content -Path $proposalFiles[0].FullName -Raw | ConvertFrom-Json            $proposal.category | Should -Be 'missing-skill'            $proposal.domain | Should -Be 'finance'            $proposal.autoApply | Should -Be $true            $logPath = Join-Path $workspace.ProposalDir 'learning-log.jsonl'            Test-Path $logPath | Should -Be $true            (Get-Content -Path $logPath -Raw) -match 'isolated-learning-proposals' | Should -Be $true        }    }    Context 'Summary parsing and no-commit analysis' {        It 'handles malformed startup summary and records no-commit analysis in an isolated git repo' {            $workspace = New-TestWorkspace -Path $script:tempRoot -CreateSummaryDir            $skillsIndexPath = Join-Path $workspace.SkillsDir 'SKILL_INDEX.md'            $businessSkillIndexPath = Join-Path $workspace.BusinessDir 'SKILL.md'            $summaryPath = Join-Path $script:tempRoot 'scripts\.session\startup-summary.json'            @"- `testing-skill`"@ | Set-Content -Path $skillsIndexPath -Encoding UTF8            @"**sales**"@ | Set-Content -Path $businessSkillIndexPath -Encoding UTF8            New-Item -ItemType Directory -Path (Join-Path $workspace.BusinessDir 'sales') -Force | Out-Null            '{invalid-json' | Set-Content -Path $summaryPath -Encoding UTF8            Push-Location $script:tempRoot            try {                git init | Out-Null                git config user.email 'tests@gentle-vanguard.local'                git config user.name 'Gentle-Vanguard Tests'                'seed' | Set-Content -Path (Join-Path $script:tempRoot 'seed.txt') -Encoding UTF8                git add . | Out-Null                $env:GIT_AUTHOR_DATE = '2000-01-01T00:00:00Z'                $env:GIT_COMMITTER_DATE = '2000-01-01T00:00:00Z'                git commit -m 'test: seed workspace' | Out-Null            }            finally {                Remove-Item Env:GIT_AUTHOR_DATE -ErrorAction SilentlyContinue                Remove-Item Env:GIT_COMMITTER_DATE -ErrorAction SilentlyContinue                Pop-Location            }            $env:GENTLE_VANGUARD_BASE_DIR = $script:tempRoot            $null = & $script:postSessionLearning -SessionId 'isolated-learning-no-commits' -NoExit 2>&1            $logPath = Join-Path $workspace.ProposalDir 'learning-log.jsonl'            Test-Path $logPath | Should -Be $true            $logEntry = Get-Content -Path $logPath -Raw | ConvertFrom-Json            $logEntry.sessionId | Should -Be 'isolated-learning-no-commits'            $logEntry.commits | Should -Be 0            $proposalFiles = @(Get-ChildItem -Path $workspace.ProposalDir -Filter 'prop-*.json' -ErrorAction SilentlyContinue)            $proposalFiles.Count | Should -Be 0        }    }}


